/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * In this demo, "sending" means storing the SMS in an in-memory log.
 * A real implementation would use an SMS gateway API (e.g., Twilio).
 *
 * NOTE: The User model currently has no `phone` field.
 * Until user preferences are updated to support multiple notification
 * channels (including phone numbers), the recipient will be whatever
 * the NotificationService provides (typically an email address).
 * See the warning posted to the project blackboard for details on
 * what needs to change in user preferences.
 */

import type { NotificationAdapter, NotificationPayload } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

export interface SentSms {
  to: string;
  body: string;
  sentAt: Date;
}

export type SmsSendFn = (to: string, body: string) => Promise<{ success: boolean; messageId?: string }>;

export class SmsAdapter implements NotificationAdapter {
  readonly name = 'sms';
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];
  private smsSend: SmsSendFn;

  constructor(smsSend?: SmsSendFn) {
    this.smsSend = smsSend ?? (async (_to: string, _body: string) => ({ success: true }));
  }

  async send(payload: NotificationPayload): Promise<void> {
    const smsBody = `${payload.subject}: ${payload.body}`;

    let success = false;
    try {
      const result = await this.smsSend(payload.recipient, smsBody);
      success = result.success;
    } catch (error) {
      this.logger.error(`SMS delivery failed to ${payload.recipient}: ${error}`);
    }

    const sms: SentSms = {
      to: payload.recipient,
      body: smsBody,
      sentAt: payload.sentAt,
    };
    this.sentMessages.push(sms);

    if (success) {
      this.logger.info(`SMS sent to ${payload.recipient}: ${payload.subject}`);
    } else {
      this.logger.warn(`SMS delivery to ${payload.recipient} failed`);
    }
  }

  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/adapters/notification.adapter.js';
import type { SmsSendFn } from '../../src/adapters/sms.adapter.js';

describe('SmsAdapter', () => {
  let mockSend: SmsSendFn;
  let adapter: SmsAdapter;

  const samplePayload: NotificationPayload = {
    id: 'notif-0001',
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed.',
    sentAt: new Date('2026-01-15T10:00:00Z'),
  };

  beforeEach(() => {
    mockSend = vi.fn().mockResolvedValue({ success: true, messageId: 'msg-001' });
    adapter = new SmsAdapter(mockSend);
  });

  it('should have name "sms"', () => {
    expect(adapter.name).toBe('sms');
  });

  it('should call the SMS send function with recipient and combined body', async () => {
    await adapter.send(samplePayload);

    expect(mockSend).toHaveBeenCalledOnce();
    expect(mockSend).toHaveBeenCalledWith(
      '+15551234567',
      'Order Confirmation: order-1: Your order has been placed.',
    );
  });

  it('should store sent SMS message', async () => {
    await adapter.send(samplePayload);

    const messages = adapter.getSentMessages();
    expect(messages).toHaveLength(1);
    expect(messages[0]?.to).toBe('+15551234567');
    expect(messages[0]?.body).toBe('Order Confirmation: order-1: Your order has been placed.');
    expect(messages[0]?.sentAt).toEqual(new Date('2026-01-15T10:00:00Z'));
  });

  it('should track multiple messages', async () => {
    await adapter.send(samplePayload);
    await adapter.send({ ...samplePayload, recipient: '+15559876543' });

    expect(adapter.getSentMessages()).toHaveLength(2);
  });

  it('should clear sent messages', async () => {
    await adapter.send(samplePayload);
    adapter.clearSentMessages();

    expect(adapter.getSentMessages()).toHaveLength(0);
  });

  it('should handle send failure gracefully', async () => {
    mockSend = vi.fn().mockResolvedValue({ success: false });
    adapter = new SmsAdapter(mockSend);

    await adapter.send(samplePayload);

    const messages = adapter.getSentMessages();
    expect(messages).toHaveLength(1);
    expect(messages[0]?.to).toBe('+15551234567');
  });

  it('should handle send error gracefully', async () => {
    mockSend = vi.fn().mockRejectedValue(new Error('Gateway timeout'));
    adapter = new SmsAdapter(mockSend);

    await adapter.send(samplePayload);

    const messages = adapter.getSentMessages();
    expect(messages).toHaveLength(1);
    expect(messages[0]?.to).toBe('+15551234567');
  });

  it('should work with default send function (no constructor arg)', async () => {
    const defaultAdapter = new SmsAdapter();

    await defaultAdapter.send(samplePayload);

    const messages = defaultAdapter.getSentMessages();
    expect(messages).toHaveLength(1);
  });
});
